const item = $input.first();
const webhookData = $('Webhook').first().json.body;

// Check if we have binary data
if (!item.binary || !item.binary.data) {
  throw new Error('No binary data received from Download Image node');
}

const binary = item.binary.data;

// Validate it's an image
if (!binary.mimeType || !binary.mimeType.startsWith('image/')) {
  throw new Error('Only image files are supported.');
}

// Get timestamp for unique filename
const timestamp = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);

// Get extension from mime type
let extension = 'jpg';
if (binary.mimeType === 'image/png') extension = 'png';
else if (binary.mimeType === 'image/jpeg') extension = 'jpg';
else if (binary.mimeType === 'image/webp') extension = 'webp';

const userId = webhookData.userId || 'user';
const fileName = `invoice_${timestamp}_${userId}.${extension}`;

// IMPORTANT: Keep the exact binary structure for Google Drive
return {
  json: {
    fileName: fileName,
    mimeType: binary.mimeType,
    originalUrl: webhookData.imageUrl,
    userId: userId
  },
  binary: item.binary  // Pass the ENTIRE binary object unchanged
};

// Get OpenAI response
const openAIData = $input.first().json;

// Extract the response content
let response = openAIData.choices[0].message.content;

// Parse JSON response
let extracted;
try {
  // Remove markdown code blocks if present
  const cleanResponse = response.replace(/```(?:json)?\s*([\s\S]*?)```/g, '$1').trim();
  extracted = JSON.parse(cleanResponse);
} catch (e) {
  throw new Error('OpenAI did not return valid JSON. Response: ' + response);
}

// Validate required fields
if (!extracted.company_name || extracted.company_name === null) {
  throw new Error('Could not extract company name from invoice.');
}

if (!extracted.amount || extracted.amount === null || extracted.amount === 0) {
  throw new Error('Could not extract amount from invoice.');
}

if (!extracted.date || extracted.date === null) {
  throw new Error('Could not extract date from invoice.');
}

// Get Google Drive file info
const driveData = $('Upload to Google Drive').first().json;
const driveUrl = `https://drive.google.com/file/d/${driveData.id}/view`;

// Format and return data
return {
  json: {
    company_name: extracted.company_name,
    amount: parseFloat(extracted.amount),
    currency: extracted.currency || 'EUR',
    date: extracted.date,
    category: extracted.category || 'Other',
    processed_at: new Date().toISOString(),
    drive_file_id: driveData.id,
    drive_url: driveUrl,
    file_name: driveData.name
  }
};

